// SEO Report Automation — Data Extraction & Transformation
// Input: parsed CSV rows | Output: all report placeholder values (counts + dynamic fix text)

const items = $input.all();
const rows = items.map(item => item.json);

// Get filename from trigger node
const filename = $('Google Drive Trigger').first().json.name;

// Parse filename: dneresources.com_issues_20260309.csv
const parts = filename.replace('.csv', '').split('_issues_');
const clientUrl = parts[0] || 'Unknown';
const dateRaw = parts[1] || '';

// Format date: 20260309 -> March 9, 2026
let reportDate = dateRaw;
if (dateRaw && dateRaw.length === 8) {
  const y = dateRaw.substring(0, 4);
  const m = parseInt(dateRaw.substring(4, 6));
  const d = parseInt(dateRaw.substring(6, 8));
  const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  reportDate = months[m - 1] + ' ' + d + ', ' + y;
}

// Client name mapping — ADD MORE CLIENTS HERE
const nameMap = {
  'dneresources.com': 'DNE Resources'
};
const clientName = nameMap[clientUrl] || clientUrl;

// Helper: get Failed checks count by issue name (case-insensitive)
function fc(name) {
  const r = rows.find(x => x['Issue'] && x['Issue'].trim().toLowerCase() === name.toLowerCase());
  return r ? (parseInt(r['Failed checks']) || 0) : 0;
}

// Helper: build detail text for grouped issues
function detail(names) {
  const lines = names.filter(n => fc(n) > 0).map(n => '- ' + n + ': ' + fc(n));
  return lines.length > 0 ? lines.join('\n') : 'No issues found.';
}

// === HREFLANG ===
const hreflangNames = [
  'Hreflang conflicts within page source code',
  'Issues with incorrect hreflang links',
  'Issues with hreflang values',
  'Hreflang language mismatch issues'
];
const hreflangCount = hreflangNames.reduce((s, n) => s + fc(n), 0);

// === SITEMAP ===
const sitemapNames = [
  'Invalid sitemap.xml format',
  'Incorrect pages found in sitemap.xml',
  'Sitemap file too large',
  'Sitemap.xml not specified in robots.txt',
  'Sitemap.xml not found',
  'HTTP URLs in sitemap.xml for HTTPS site'
];
const sitemapCount = sitemapNames.reduce((s, n) => s + fc(n), 0);

// === HSTS ===
const hstsCount = fc('No HSTS support');

// ============================================================
// === DYNAMIC FIX TEXT (targeted per issue, clear if none) ===
// ============================================================

// fix_4xx
const fix4xx = fc('4xx errors') > 0
  ? "Identify each broken URL in SEMrush's 4xx report. Set up 301 redirects from the broken URL to the correct live destination. Update internal links on your site that point directly to 4xx URLs \u2014 don't rely solely on the redirect. Resubmit your sitemap after fixes are in place."
  : '\u2705 No 4xx errors detected.';

// fix_broken_links
const fixBrokenLinks = fc('Broken internal links') > 0
  ? "For each broken link, either restore the missing page, set up a 301 redirect to the correct destination, or update the anchor link on the source page to point to a valid URL. Avoid using redirects as a permanent fix where the original content can be restored."
  : '\u2705 No broken internal links detected.';

// fix_hreflang \u2014 dynamically includes only the sub-issues present
let fixHreflang = '';
const hreflangConflictsCount = fc('Hreflang conflicts within page source code');
const hreflangIncorrectCount = fc('Issues with incorrect hreflang links');
if (hreflangConflictsCount > 0) {
  fixHreflang += "Hreflang conflicts (page source): Resolve conflicting hreflang annotations \u2014 ensure only one hreflang annotation per language-region per page. Audit each affected page's HTML head section for duplicate or contradictory hreflang tags and remove conflicts.";
}
if (hreflangIncorrectCount > 0) {
  if (fixHreflang) fixHreflang += '\n\n';
  fixHreflang += "Incorrect hreflang links: Fix broken hreflang URLs that return non-200 status codes. Fix hreflang redirects \u2014 hreflang attributes must point to the final destination URL, not a redirected one. Replace any relative URLs with absolute URLs including the full domain.";
}
if (!fixHreflang) fixHreflang = '\u2705 No hreflang issues detected.';

// fix_sitemap
const fixSitemap = sitemapCount > 0
  ? "Review your sitemap.xml for any redirected, non-canonical, or non-200 URLs. Each URL in your sitemap should be the canonical version of the page and return a 200 status code. Remove URLs that lead to duplicate content, redirect chains, or 4xx responses \u2014 provide only final destination URLs that Google should index."
  : '\u2705 No sitemap issues detected.';

// fix_missing_alt
const fixMissingAlt = fc('Missing ALT attributes') > 0
  ? 'Add descriptive ALT text to every image flagged. ALT text should accurately describe the image content in 5\u201315 words and naturally incorporate relevant keywords where appropriate. Avoid keyword stuffing or generic values like "image" or the filename.'
  : '\u2705 No missing ALT attributes detected.';

// fix_single_link
const fixSingleLink = fc('Pages with only one internal link') > 0
  ? 'Pages with a single inbound internal link are poorly integrated into your site structure and receive minimal link equity. Identify related content and add contextual internal links pointing to these pages. Consider adding them to category pages, navigation menus, or related-content blocks.'
  : '\u2705 No under-linked pages detected.';

// fix_hsts
const fixHsts = hstsCount > 0
  ? 'Enable HTTP Strict Transport Security by adding the Strict-Transport-Security header to your server configuration with a minimum max-age of 31536000 (1 year). This instructs browsers to connect only via HTTPS and prevents SSL-stripping attacks.'
  : '\u2705 HSTS is properly configured.';

// fix_duplicate_meta
const fixDuplicateMeta = fc('Duplicate meta descriptions') > 0
  ? "Each page must have a unique meta description between 150\u2013160 characters. Duplicate meta descriptions confuse search engines about which page to surface for a given query. Rewrite duplicates to accurately summarize each page's unique content and include its primary target keyword."
  : '\u2705 No duplicate meta descriptions detected.';

// fix_duplicate_h1
const dupH1Count = fc('Multiple h1 tags') + fc('Duplicate content in h1 and title');
const fixDuplicateH1 = dupH1Count > 0
  ? "Ensure each page has exactly one H1 tag, and that it is distinct from the page's title tag. The H1 and title serve different purposes \u2014 the title is the SERP headline, the H1 is the on-page heading. Duplicating them wastes an opportunity to target additional keyword variations."
  : '\u2705 No duplicate H1 issues detected.';

// fix_duplicate_title
const fixDuplicateTitle = fc('Duplicate title tag') > 0
  ? "Each page must have a unique title tag. Duplicate titles signal to Google that pages contain similar or identical content, suppressing rankings for both. Rewrite duplicates to reflect each page's specific content and primary keyword \u2014 keep titles between 50\u201360 characters."
  : '\u2705 No duplicate title tags detected.';

// fix_missing_meta
const fixMissingMeta = fc('Missing meta description') > 0
  ? "Add a unique meta description (150\u2013160 characters) to every page flagged. While meta descriptions are not a direct ranking factor, they influence click-through rate from the SERP. Each description should summarize the page's content, include the primary keyword naturally, and include a call to action where relevant."
  : '\u2705 No pages are missing meta descriptions.';

// fix_title_length
const titleShort = fc('Title element is too short');
const titleLong = fc('Title element is too long');
const fixTitleLength = (titleShort > 0 || titleLong > 0)
  ? 'Keep title tags between 50\u201360 characters. Titles under 30 characters miss keyword opportunities and appear sparse in search results. Titles over 60 characters are truncated by Google in the SERP. Rewrite outliers to be descriptive, keyword-rich, and within the optimal range.'
  : '\u2705 All title tag lengths are within optimal range.';

// fix_underscores
const fixUnderscores = fc('Underscores in URL') > 0
  ? 'Replace underscores (_) with hyphens (-) in all URL slugs flagged. Google treats hyphens as word separators but treats underscores as word joiners \u2014 meaning seo_tips is read as one word, while seo-tips is correctly read as two words. This impacts keyword matching in URL-based ranking signals.'
  : '\u2705 No underscores in URL slugs detected.';

// fix_anchor_text
const fixAnchorText = fc('Links with non-descriptive anchor text') > 0
  ? 'Replace generic anchor text phrases ("click here", "read more", "learn more") with descriptive text that reflects the content of the destination page. Anchor text is a relevancy signal \u2014 descriptive anchors help search engines understand the topic of the linked page and improve internal link equity distribution.'
  : '\u2705 No non-descriptive anchor text detected.';

// fix_redirects
const fixRedirects = fc('Permanent redirects') > 0
  ? "Update internal links that currently point to redirected URLs so they link directly to the final destination. Redirect chains add latency and dilute link equity \u2014 each additional hop reduces the amount of PageRank passed. Fix the source link; don't rely solely on the redirect being in place."
  : '\u2705 No redirect chain issues detected.';

return [{
  json: {
    // === EXISTING 22 PLACEHOLDERS ===
    report_date: reportDate,
    client_name: clientName,
    client_url: clientUrl,
    site_health_score: '[ENTER SITE HEALTH SCORE]',
    hreflang_conflicts_count: String(hreflangCount),
    hreflang_conflicts_detail: detail(hreflangNames),
    sitemap_issues_count: String(sitemapCount),
    sitemap_issues_detail: detail(sitemapNames),
    broken_internal_links_count: String(fc('Broken internal links')),
    missing_alt_count: String(fc('Missing ALT attributes')),
    single_incoming_link_count: String(fc('Pages with only one internal link')),
    hsts_issues: hstsCount > 0 ? 'No HSTS support: ' + hstsCount + ' issue(s)' : 'No issues found.',
    duplicate_meta_desc_count: String(fc('Duplicate meta descriptions')),
    duplicate_h1_count: String(fc('Multiple h1 tags') + fc('Duplicate content in h1 and title')),
    duplicate_title_count: String(fc('Duplicate title tag')),
    missing_meta_desc_count: String(fc('Missing meta description')),
    title_length_short_count: String(fc('Title element is too short')),
    title_length_long_count: String(fc('Title element is too long')),
    url_underscore_count: String(fc('Underscores in URL')),
    non_descriptive_anchor_count: String(fc('Links with non-descriptive anchor text')),
    errors_4xx_count: String(fc('4xx errors')),
    permanent_redirects_count: String(fc('Permanent redirects')),
    // === 15 DYNAMIC FIX TEXT PLACEHOLDERS ===
    fix_4xx: fix4xx,
    fix_broken_links: fixBrokenLinks,
    fix_hreflang: fixHreflang,
    fix_sitemap: fixSitemap,
    fix_missing_alt: fixMissingAlt,
    fix_single_link: fixSingleLink,
    fix_hsts: fixHsts,
    fix_duplicate_meta: fixDuplicateMeta,
    fix_duplicate_h1: fixDuplicateH1,
    fix_duplicate_title: fixDuplicateTitle,
    fix_missing_meta: fixMissingMeta,
    fix_title_length: fixTitleLength,
    fix_underscores: fixUnderscores,
    fix_anchor_text: fixAnchorText,
    fix_redirects: fixRedirects
  }
}];

const staticData = $getWorkflowStaticData('global');
const item = $input.first();
const fileId = item.json.id;
const now = Date.now();

if (!staticData.seenFiles) {
  staticData.seenFiles = {};
}

// Clean up entries older than 1 hour
for (const id of Object.keys(staticData.seenFiles)) {
  if (now - staticData.seenFiles[id] > 3600000) {
    delete staticData.seenFiles[id];
  }
}

// If same file ID seen within last 10 minutes, stop execution
if (staticData.seenFiles[fileId] && (now - staticData.seenFiles[fileId]) < 600000) {
  return [];
}

// New file — mark as seen and continue
staticData.seenFiles[fileId] = now;
return $input.all();

const item = $input.first().json;
let errorMessage = '', failedNode = '', executionId = '', executionUrl = '', mode = '';
let workflowName = item.workflow?.name || 'Unknown';
let workflowId = item.workflow?.id || 'Unknown';
if (item.execution) {
  errorMessage = item.execution.error?.message || 'Unknown';
  failedNode = item.execution.lastNodeExecuted || 'Unknown';
  executionId = item.execution.id || 'N/A';
  executionUrl = item.execution.url || 'N/A';
  mode = item.execution.mode || 'Unknown';
} else if (item.trigger) {
  errorMessage = item.trigger.error?.message || 'Unknown';
  failedNode = 'Trigger Node (workflow did not execute)';
  executionId = 'N/A (trigger-level failure)';
  executionUrl = 'N/A (trigger-level failure)';
  mode = item.trigger.mode || 'trigger';
}
return [{ json: { workflowName, workflowId, errorMessage, failedNode, executionId, executionUrl, mode } }];
